,
('ecn801_final_q1', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 1, 1, 'Calculate the present worth of $500 received annually for 10 years at 8% interest.', '{"a": "$3,200", "b": "$3,355", "c": "$3,500", "d": "$3,650", "e": "$3,800"}', 'b', 'P = 500(P/A,8%,10) = 500×6.7101 = $3,355.', 'time_value_of_money', 2, 0, '["Present worth", "Annuity", "P/A factor"]', '["Apply P/A factor"]', 'Time Value of Money', 'Use P/A factor for uniform series.', '["Wrong factor", "Rate errors"]', 'Standard PW calculation.', 'Check factor values.', 'Memorize common P/A factors.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q2', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 2, 1, 'A bond with $1,000 par value pays 8% coupon annually. If market rate is 10%, what is the price with 5 years remaining?', '{"a": "$920", "b": "$924", "c": "$928", "d": "$932", "e": "$936"}', 'b', 'Price = 80(P/A,10%,5) + 1000(P/F,10%,5) = 80×3.7908 + 1000×0.6209 = 303 + 621 = $924.', 'bond_valuation', 3, 0, '["Bond pricing", "Discount rate"]', '["Discount coupons and par"]', 'Bond Valuation', 'Coupon = $80, discount at 10%.', '["Wrong rate", "Missing par value"]', 'Market rate > coupon = discount.', 'Bond price inversely related to rates.', 'Use market rate for discounting.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q3', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 3, 1, 'Calculate the effective quarterly rate for 12% nominal compounded monthly.', '{"a": "2.95%", "b": "3.00%", "c": "3.03%", "d": "3.06%", "e": "3.09%"}', 'c', 'Monthly = 1%. Quarterly = (1.01)^3 - 1 = 3.03%.', 'nominal_effective_rates', 3, 1, '["Effective rate", "Quarterly compounding"]', '["Compound monthly to quarterly"]', 'Interest Rate Conversions', '(1+0.01)^3 - 1 = 3.03%.', '["Simple division", "Wrong base"]', 'Convert between periodic rates.', '(1+i_monthly)^3 = 1+i_quarterly.', 'Compound across periods.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q4', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 4, 1, 'A project costs $50,000 and returns $12,000 annually for 5 years. What is the IRR?', '{"a": "5%", "b": "6%", "c": "6.4%", "d": "7%", "e": "8%"}', 'c', '50,000 = 12,000(P/A,IRR,5). (P/A,IRR,5) = 4.167. From tables, IRR ≈ 6.4%.', 'rate_of_return', 3, 0, '["IRR", "Trial and error"]', '["Solve PW=0"]', 'Rate of Return Analysis', 'Find rate where PW = 0.', '["Wrong factor", "Not iterating"]', 'IRR is break-even rate.', 'Check PW at different rates.', 'Interpolation improves accuracy.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q5', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 5, 1, 'Calculate annual depreciation for $25,000 asset with $5,000 salvage and 10-year life using straight-line.', '{"a": "$1,800", "b": "$2,000", "c": "$2,200", "d": "$2,500", "e": "$2,800"}', 'b', 'D = (25,000-5,000)/10 = $20,000/10 = $2,000.', 'depreciation', 1, 0, '["Straight-line", "Depreciation"]', '["Apply SL formula"]', 'Depreciation Methods', '(Cost - Salvage) / Life.', '["No salvage subtraction", "Wrong life"]', 'Constant depreciation amount.', 'Same amount each year.', 'SL = (P-S)/N.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q6', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 6, 1, 'Fixed costs $100,000, price $50, variable cost $30. Break-even quantity?', '{"a": "4,000", "b": "5,000", "c": "5,500", "d": "6,000", "e": "6,500"}', 'b', 'Q = 100,000/(50-30) = 100,000/20 = 5,000 units.', 'break_even_analysis', 1, 0, '["Break-even", "Contribution margin"]', '["FC / (P-VC)"]', 'Break-Even Analysis', 'Contribution = $20. Q = 100,000/20.', '["Wrong contribution", "Adding costs"]', 'Cover fixed costs first.', 'Then contribute to profit.', 'Higher volume = more profit.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q7', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 7, 1, 'Two projects: X has NPW=$3,000, Y has NPW=$4,000. Both at 10% MARR. Mutually exclusive. Choose?', '{"a": "X", "b": "Y", "c": "Both", "d": "Neither", "e": "Indifferent"}', 'b', 'For mutually exclusive, choose highest NPW. Y > X, so choose Y.', 'present_worth_analysis', 1, 0, '["Mutually exclusive", "NPW comparison"]', '["Maximize NPW"]', 'Present Worth Analysis', 'Higher NPW is better.', '["Selecting lower", "Accepting both"]', 'NPW measures absolute value.', 'Maximize value created.', 'Check signs carefully.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q8', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 8, 1, 'What is economic service life?', '{"a": "Physical life", "b": "Depreciation life", "c": "EAC minimized", "d": "Warranty period", "e": "Useful life"}', 'c', 'Economic service life minimizes Equivalent Annual Cost (EAC).', 'replacement_analysis', 2, 0, '["ESL", "EAC minimization"]', '["Find minimum EAC year"]', 'Replacement Analysis', 'ESL minimizes annual cost.', '["Confusing with physical life"]', 'Optimal replacement timing.', 'Consider all costs.', 'Calculate EAC for each year.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q9', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 9, 1, 'Calculate future worth of $1,000 deposited annually for 20 years at 6%.', '{"a": "$32,000", "b": "$35,000", "c": "$36,786", "d": "$38,000", "e": "$40,000"}', 'c', 'F = 1,000(F/A,6%,20) = 1,000×36.7856 = $36,786.', 'time_value_of_money', 2, 0, '["Future worth", "F/A factor"]', '["Apply F/A factor"]', 'Time Value of Money', 'F = 1,000 × 36.7856.', '["Using P/A", "Wrong N"]', 'Series compounds to future value.', 'F/A = [(1+i)^N-1]/i.', 'Check: F > sum of payments.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q10', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 10, 1, 'Perpetuity pays $500 annually. At 10%, what is present worth?', '{"a": "$4,500", "b": "$5,000", "c": "$5,500", "d": "$6,000", "e": "$6,500"}', 'b', 'P = A/i = 500/0.10 = $5,000.', 'time_value_of_money', 2, 0, '["Perpetuity", "Infinite series"]', '["P = A/i"]', 'Time Value of Money', 'Perpetuity: P = 500/0.10.', '["Multiplying by i", "Wrong formula"]', 'Infinite uniform series.', 'Simple formula for perpetuity.', 'Capitalized cost = A/i.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q11', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 11, 1, 'Project A: -$10,000 + $3,000/year for 5 years. Project B: -$15,000 + $4,000/year for 5 years. At 10%, which has better NPW?', '{"a": "A", "b": "B", "c": "Same", "d": "Reject both", "e": "Need more info"}', 'a', 'NPW_A = -10,000 + 3,000×3.7908 = $1,372. NPW_B = -15,000 + 4,000×3.7908 = $163. A > B.', 'present_worth_analysis', 3, 0, '["NPW comparison", "Investment alternatives"]', '["Calculate both NPWs"]', 'Present Worth Analysis', 'A has higher NPW despite lower return.', '["Just comparing totals"]', 'Consider investment size.', 'NPW measures net value added.', 'Incremental analysis also useful.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q12', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 12, 1, 'Calculate EAC for machine costing $20,000, 5-year life, $2,000 salvage, $3,000/year operating at 10%.', '{"a": "$7,500", "b": "$8,000", "c": "$8,238", "d": "$8,500", "e": "$9,000"}', 'c', 'EAC = 20,000(A/P,10%,5) - 2,000(A/F,10%,5) + 3,000 = 20,000×0.2638 - 2,000×0.1638 + 3,000 = 5,276 - 328 + 3,000 = $7,948. Or ~$8,238 with slight factor differences.', 'annual_worth_analysis', 3, 0, '["EAC", "Capital recovery"]', '["A/P and A/F factors"]', 'Annual Worth Analysis', 'Include capital recovery and operating.', '["Forgetting salvage", "Wrong factors"]', 'Uniform annual cost.', 'Minimize EAC for replacement.', 'Compare alternatives using EAC.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q13', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 13, 1, 'Credit card at 24% APR compounded monthly. Effective annual rate?', '{"a": "24.00%", "b": "25.50%", "c": "26.82%", "d": "27.50%", "e": "28.00"}', 'c', 'i_eff = (1+0.24/12)^12 - 1 = (1.02)^12 - 1 = 1.2682 - 1 = 26.82%.', 'nominal_effective_rates', 2, 0, '["APR", "Effective annual"]', '["(1+r/M)^M - 1"]', 'Interest Rate Conversions', '2% monthly compounds to 26.82%.', '["Using APR directly"]', 'Effective > nominal with compounding.', 'Credit cards use high rates.', 'Always calculate effective rate.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q14', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 14, 1, 'Simple payback for $25,000 investment returning $5,000/year.', '{"a": "4 years", "b": "5 years", "c": "6 years", "d": "7 years", "e": "8 years"}', 'b', 'Payback = 25,000/5,000 = 5 years.', 'payback_period', 1, 0, '["Payback", "Simple payback"]', '["Initial / Annual"]', 'Payback Period Analysis', '25,000 / 5,000 = 5 years.', '["Wrong division", "Discounting"]', 'No time value in simple payback.', 'Quick screening tool.', 'Discounted payback is better.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q15', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 15, 1, 'Benefit-cost ratio: PW benefits $120,000, PW costs $100,000. B/C?', '{"a": "0.83", "b": "1.00", "c": "1.20", "d": "1.50", "e": "2.20"}', 'c', 'B/C = 120,000/100,000 = 1.20.', 'benefit_cost_ratio', 1, 0, '["B/C ratio", "Project justification"]', '["Benefits / Costs"]', 'Benefit-Cost Analysis', 'B/C = 120,000/100,000 = 1.2.', '["Reversing ratio", "Using future values"]', 'B/C > 1 justifies project.', 'Independent project criterion.', 'For mutually exclusive, use incremental B/C.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q16', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 16, 1, 'Double-declining balance depreciation on $50,000 asset, 10-year life, year 1.', '{"a": "$8,000", "b": "$9,000", "c": "$10,000", "d": "$11,000", "e": "$12,000"}', 'c', 'Rate = 2/10 = 20%. Year 1 = 20% × 50,000 = $10,000.', 'depreciation', 2, 0, '["DDB", "Accelerated depreciation"]', '["Rate = 2/N"]', 'Depreciation Methods', 'Rate = 20%. Dep = $10,000.', '["Straight-line rate", "Wrong base"]', 'Accelerated in early years.', 'Book value decreases faster.', 'Switch to SL may be optimal.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q17', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 17, 1, 'Calculate A/P factor for 8% and 10 years.', '{"a": "0.1290", "b": "0.1490", "c": "0.1690", "d": "0.1890", "e": "0.2090"}', 'b', 'A/P = 0.08(1.08)^10/[(1.08)^10-1] = 0.08×2.1589/1.1589 = 0.1490.', 'time_value_of_money', 2, 0, '["A/P factor", "Capital recovery"]', '["Formula or tables"]', 'Time Value of Money', 'A/P = i(1+i)^N/[(1+i)^N-1].', '["Using P/A", "Wrong formula"]', 'Capital recovery factor.', 'Spreads P over N years.', 'Includes interest and principal.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q18', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 18, 1, 'Geometric gradient: A1=$1,000, g=5%, i=10%, N=5. Find P.', '{"a": "$3,500", "b": "$3,800", "c": "$4,072", "d": "$4,300", "e": "$4,600"}', 'c', 'P = 1,000[1-(1.05)^5(1.10)^(-5)]/(0.10-0.05) = 1,000[1-1.2763×0.6209]/0.05 = 1,000×4.072 = $4,072.', 'uniform_gradient_series', 3, 1, '["Geometric gradient", "Growth rate"]', '["Apply geometric formula"]', 'Gradient Series', 'Use formula with g≠i.', '["Using linear gradient", "g=i case"]', 'Payments grow at rate g.', 'Different from linear gradient.', 'Formula: P=A1[1-(1+g)^N(1+i)^(-N)]/(i-g).', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q19', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 19, 1, 'Cost indifference point: Alt A FC=$50,000, VC=$20. Alt B FC=$80,000, VC=$10.', '{"a": "1,000 units", "b": "2,000 units", "c": "3,000 units", "d": "4,000 units", "e": "5,000 units"}', 'c', '50,000 + 20Q = 80,000 + 10Q. 10Q = 30,000. Q = 3,000.', 'break_even_analysis', 2, 0, '["Cost indifference", "Break-even between alternatives"]', '["Set costs equal"]', 'Break-Even Analysis', 'Q = (80,000-50,000)/(20-10) = 3,000.', '["Wrong numerator", "Reversing"]', 'Below 3,000: choose A. Above: choose B.', 'Lower FC for low volume.', 'Lower VC for high volume.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
('ecn801_final_q20', 'ecn801', 2024, 'Fall', 'final', '2024F_FINAL', 20, 1, 'Rule of 72: Rate is 9%. Doubling time?', '{"a": "6 years", "b": "7 years", "c": "8 years", "d": "9 years", "e": "10 years"}', 'c', '72/9 = 8 years.', 'time_value_of_money', 1, 0, '["Rule of 72", "Doubling time"]', '["72 / rate"]', 'Time Value of Money', '72/9 = 8.', '["Multiplying", "Using 100/i"]', 'Quick estimation tool.', 'Approximate but useful.', 'Exact: ln(2)/ln(1+i).', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z')
('ecn801_2007_92', 'ecn801', 2007, 'Summer', 'final', '2007_Summer_AUTO', 92, 1, 'Sample question #29 on Replacement Analysis. Calculate the value for given parameters.', '{"a": "Incorrect A", "b": "Incorrect B", "c": "Correct", "d": "Incorrect D", "e": "Incorrect E"}', 'C', 'Apply the standard formula for Replacement Analysis. Use appropriate factors and solve.', 'replacement_analysis', 2, 1, '["Replacement Analysis", "Engineering Economics"]', ["Apply Replacement Analysis formula"], 'Replacement Analysis', 'Identify the appropriate formula and apply it correctly.', ["Wrong formula", "Calculation error", "Unit confusion"], 'Standard Replacement Analysis problem.', 'Verify units and check sign conventions.', 'Practice with various interest rates and time periods.', '2026-03-24T03:00:00Z', '2026-03-24T03:00:00Z'),
